// ─────────────────────────────────────────────────────────────
// Valida el payload y deduplica. Evita insertar la misma canción
// dos veces si llega repetida en menos de VENTANA_MS milisegundos.
// Esto protege contra:
//   - Mensajes MQTT retained que llegan al reconectar Node-RED
//   - Republicaciones accidentales del script Python
// ─────────────────────────────────────────────────────────────

const VENTANA_MS = 5 * 60 * 1000;  // 5 minutos
const FUENTES_VALIDAS = ['airplay', 'spotify', 'local'];

const p = msg.payload;

// 1) Validación mínima: debe haber título
if (!p || typeof p !== 'object' || !p.titulo || !String(p.titulo).trim()) {
    node.status({ fill: 'grey', shape: 'ring', text: 'payload vacío/inválido' });
    return null;
}

// 2) Validar fuente (si viene rara, la normalizamos a 'airplay')
let fuente = String(p.fuente || '').toLowerCase().trim();
if (!FUENTES_VALIDAS.includes(fuente)) {
    fuente = 'airplay';
}

// 3) Dedupe: misma canción+artista+fuente en los últimos VENTANA_MS = ignorar
const ahora = Date.now();
const key = `${p.titulo}||${p.artista || ''}||${fuente}`;
const ultimoKey = flow.get('ultimo_key');
const ultimoTs  = flow.get('ultimo_ts') || 0;

if (key === ultimoKey && (ahora - ultimoTs) < VENTANA_MS) {
    const segsRest = Math.round((VENTANA_MS - (ahora - ultimoTs)) / 1000);
    node.status({ fill: 'grey', shape: 'ring', text: `duplicado (${segsRest}s restantes)` });
    return null;
}

flow.set('ultimo_key', key);
flow.set('ultimo_ts', ahora);

// 4) Duración: puede venir null (típico en airplay al arrancar) → la dejamos NULL
let duracion = null;
if (p.duracion !== undefined && p.duracion !== null && !isNaN(parseFloat(p.duracion))) {
    duracion = parseFloat(p.duracion);
}

// 5) Preparar el INSERT parametrizado (evita SQL injection)
msg.topic = `INSERT INTO reproducciones
             (titulo, artista, album, duracion_seg, fuente)
             VALUES (?, ?, ?, ?, ?)`;

msg.payload = [
    String(p.titulo).substring(0, 255),
    String(p.artista || '').substring(0, 255),
    String(p.album   || '').substring(0, 255),
    duracion,
    fuente
];

node.status({ fill: 'blue', shape: 'dot', text: `→ ${p.titulo} (${fuente})` });
return msg;

// El nodo mysql devuelve info del INSERT en msg.payload
const r = msg.payload || {};
if (r.affectedRows >= 1) {
    node.status({ fill: 'green', shape: 'dot', text: `id=${r.insertId} ✓` });
    msg.payload = `✅ Guardado en BD · id=${r.insertId}`;
} else {
    node.status({ fill: 'yellow', shape: 'ring', text: 'sin cambios' });
    msg.payload = '⚠️  INSERT sin filas afectadas';
}
return msg;

const err = msg.error || {};
msg.payload = `❌ [${err.source && err.source.name || 'desconocido'}] ${err.message || 'error sin mensaje'}`;
node.status({ fill: 'red', shape: 'dot', text: 'error' });
return msg;
